package com.example.securelogin;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {
    
    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private SecureCredentialManager credentialManager;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);
        
        credentialManager = new SecureCredentialManager(this);
        
        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);
        
        checkExistingCredentials();
        
        loginButton.setOnClickListener(v -> performLogin());
    }
    
    private void checkExistingCredentials() {
        String savedEmail = credentialManager.getEmail();
        String savedToken = credentialManager.getAuthToken();
        
        if (savedEmail != null && savedToken != null) {
            navigateToHome();
        }
    }
    
    private void performLogin() {
        String email = emailInput.getText().toString().trim();
        String password = passwordInput.getText().toString().trim();
        
        if (email.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Please enter email and password", Toast.LENGTH_SHORT).show();
            return;
        }
        
        authenticateUser(email, password);
    }
    
    private void authenticateUser(String email, String password) {
        new Thread(() -> {
            String authToken = mockApiLogin(email, password);
            
            runOnUiThread(() -> {
                if (authToken != null) {
                    credentialManager.saveCredentials(email, authToken);
                    navigateToHome();
                } else {
                    Toast.makeText(this, "Login failed", Toast.LENGTH_SHORT).show();
                }
            });
        }).start();
    }
    
    private String mockApiLogin(String email, String password) {
        try {
            Thread.sleep(1000);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
        
        if (email.contains("@") && password.length() >= 6) {
            return "secure_token_" + System.currentTimeMillis();
        }
        return null;
    }
    
    private void navigateToHome() {
        Intent intent = new Intent(this, HomeActivity.class);
        startActivity(intent);
        finish();
    }
}

// SecureCredentialManager.java
package com.example.securelogin;

import android.content.Context;
import android.content.SharedPreferences;
import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKey;
import java.io.IOException;
import java.security.GeneralSecurityException;

public class SecureCredentialManager {
    
    private static final String PREFS_FILENAME = "secure_credentials";
    private static final String KEY_EMAIL = "user_email";
    private static final String KEY_AUTH_TOKEN = "auth_token";
    
    private SharedPreferences encryptedPrefs;
    
    public SecureCredentialManager(Context context) {
        try {
            MasterKey masterKey = new MasterKey.Builder(context)
                    .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                    .build();
            
            encryptedPrefs = EncryptedSharedPreferences.create(
                    context,
                    PREFS_FILENAME,
                    masterKey,
                    EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                    EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            );
        } catch (GeneralSecurityException | IOException e) {
            e.printStackTrace();
        }
    }
    
    public void saveCredentials(String email, String authToken) {
        if (encryptedPrefs != null) {
            encryptedPrefs.edit()
                    .putString(KEY_EMAIL, email)
                    .putString(KEY_AUTH_TOKEN, authToken)
                    .apply();
        }
    }
    
    public String getEmail() {
        if (encryptedPrefs != null) {
            return encryptedPrefs.getString(KEY_EMAIL, null);
        }
        return null;
    }
    
    public String getAuthToken() {
        if (encryptedPrefs != null) {
            return encryptedPrefs.getString(KEY_AUTH_TOKEN, null);
        }
        return null;
    }
    
    public void clearCredentials() {
        if (encryptedPrefs != null) {
            encryptedPrefs.edit().clear().apply();
        }
    }
}

// HomeActivity.java
package com.example.securelogin;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {
    
    private TextView welcomeText;
    private Button logoutButton;
    private SecureCredentialManager credentialManager;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);
        
        credentialManager = new SecureCredentialManager(this);
        
        welcomeText = findViewById(R.id.welcomeText);
        logoutButton = findViewById(R.id.logoutButton);
        
        String email = credentialManager.getEmail();
        welcomeText.setText("Welcome, " + email);
        
        logoutButton.setOnClickListener(v -> logout());
    }
    
    private void logout() {
        credentialManager.clearCredentials();
        Intent intent = new Intent(this, LoginActivity.class);
        startActivity(intent);
        finish();
    }
}

